mapper.select:
SELECT
    l.id,
    l.job_id AS jobId,
    j.app_code AS appCode,
    j.job_name AS jobName,
    l.trigger_time AS triggerTime,
    l.finish_time AS finishTime,
    l.trigger_type AS triggerType,
    l.executor_address AS executorAddress,
    l.status,
    l.attempt_no AS attemptNo,
    l.error_message AS errorMessage,
    l.trace_id AS traceId
FROM job_fire_log l
LEFT JOIN job_info j ON l.job_id = j.id


        AND l.id = #{request.logId}


        AND l.job_id = #{request.jobId}


        AND j.app_code = #{request.appCode}


        AND l.status = #{request.status}


        AND l.trigger_time >= #{request.startTriggerTime}


        AND l.trigger_time <= #{request.endTriggerTime}


ORDER BY l.trigger_time DESC

    LIMIT #{request.size} OFFSET ${(request.current - 1) * request.size}

SELECT COUNT(*)
FROM job_fire_log l
LEFT JOIN job_info j ON l.job_id = j.id


